/**
 * Generate People Data Labs firewall config.
 *
 * Data source: https://docs.peopledatalabs.com/docs/authentication
 *
 * People Data Labs accepts API keys in the X-Api-Key header.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.peopledatalabs.com/docs/authentication";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffee00";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from People Data Labs API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:people-data-labs",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const peopleDataLabsFirewall = {",
    '  name: "people-data-labs",',
    '  description: "People Data Labs API",',
    "  placeholders: {",
    `    PEOPLE_DATA_LABS_API_KEY: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://api.peopledatalabs.com",',
    "      auth: {",
    "        headers: {",
    '          "X-Api-Key": "${{ secrets.PEOPLE_DATA_LABS_API_KEY }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];

  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating People Data Labs firewall config...");
  const ts = generateTypeScript();
  writeOutput("people-data-labs", ts, import.meta.dirname);
}
